"""This module provides functions for structural checks and calculations
according to the EN 1992-1-1:2023 standard for concrete structures.
"""

from structuralcodes.codes.ec2_2023 import _section5_materials as mat5
from structuralcodes.codes.ec2_2023 import _section9_sls as sls9

from fhecor_structuralcodes.EN1992_1_1_2023 import _section_8_2_shear_2023 as _sec8_2
from fhecor_structuralcodes.EN1992_1_1_2023 import article_9_ec2_2023 as _sls9
from fhecor_structuralcodes.log_printer import Log


# 8.2 SHEAR
def shear_checks(
    bw, h, Asl, Ap, ds, dp, Asw_s, Ned, Ved, Med, fck, fyk, gamma_c, gamma_s, gamma_v, d_lower, theta, ep, rho_w, Ac
):
    """Calculates a section according to section 8.2 for shear.

    Args:
        bw (float): Width of the cross-section of linear members in mm.
        h (float): Height of the cross-section of linear members in mm.
        Asl (float): Effective area of tensile reinforcement at the distance d beyond the section considered in mm.
        Ap (float, optional):
        ds (float): Centroid of tensile reinforcement to most compression fibre
        dp (float, optional): Centroid of prestressing to most compression fibre
        Asw_s (float):
        Ned (float, optional): Axial force that accompanies Ved
        Ved (float): Design shear force at the control section in linear members. Except where concentrated loads
                     are applied at a distance less than d from the support the detailed verification of the shear
                     resistance may be omitted for control sections that are closer than d from the face of the support
        Med (float, optional): Bending moment that accompanies Ved
        fck (float): Characteristic compressive strength of concrete in MPa.
        fyk (float): Characteristic yield strength of steel in MPa.
        gamma_c (float, optional): Partial factor for concrete (Default 1.5).
        gamma_s (float, optional: Partial factor for reinforcement (Default 1.15).
        gamma_v (float, optional): Partial factor for shear design according to Table 4.3 (NDP) or Tables A.1 (NDP) and
                                   A.2 (NDP) (Default 1.4).
        d_lower (float, optional):
        theta (float, optional):
        ep (float, optional):  Eccentricity of the prestressing force or of the external load that produces the
                               compressive axial force with respect to the centre of gravity of the cross-section
                               considered as positive towards the tensile side, in mm.
        rho_w (float):
        Ac (float, optional): Area of concrete section


    Returns:
        tuple: (result, logs)
            result (dict): Dictionary with the results of the calculation.
            logs (list): List of logs describing the process.
    """
    results = {}
    logs = []
    logs.append(Log('8.2 Shear according to EN 1992-1-1:2023', color='cyan', upper_case=True))
    logs.append(Log('Assumptions', color='cyan', upper_case=True))

    d = _sec8_2.d_eff_p(ds, Asl, dp, Ap)  # is the effective depth of the flexural reinforcement
    tau_ed = _sec8_2.tao_Ed(Ved, bw, d)
    fyd = fyk / gamma_s

    # optional parameters
    if d_lower is None:
        d_lower = 24
        logs.append(Log(f'- d_lower = {d_lower:0.2f} mm', indent=1))
    tau_rdc_min = _sec8_2.tau_rdc_min(gamma_v, fck, fyd, d, d_lower)

    if Ac is None:
        if (bw is not None) and (h is not None):  # rectangular
            Ac = bw * h
            logs.append(Log(f'- rectangular section. Ac = bw·h = {Ac} mm²', indent=1))
        else:  # circular
            logs.append(Log('- circular section', indent=1))
            pass  # TODO
    else:
        logs.append(Log(f'- generic section. Ac = {Ac} mm²', indent=1))
    z = 0.9 * d  # is the lever arm for the shear stress calculation
    logs.append(Log(f'- z = 0.9·d = {z:0.1f} mm', indent=1))

    # 8.2.2 Detailed verification for members without shear reinforcement
    rho_l = _sec8_2.rho_l(Asl, bw, d)
    ddg = min(40, 16 + d_lower) if fck < 60 else min(40, 16 + d_lower * (60 / fck) ** 2)

    # eq 8.32
    tau_rdc_0 = _sec8_2.tau_Rdc_0(gamma_v, rho_l, fck, d, ddg)
    alpha_cs0 = _sec8_2.a_cs(Med, Ved, d)
    k1 = _sec8_2.k1(alpha_cs0, ep, Ac, bw, z, d)
    sigma_cp = Ned / Ac
    tau_rdc_max = _sec8_2.tau_Rdc_max(tau_rdc_0, alpha_cs0, d)
    tau_rdc_min = _sec8_2.tau_rdc_min(gamma_v, fck, fyd, d, d_lower)
    tau_rdc_comp = _sec8_2.tau_Rdc_comp(tau_rdc_0, k1, sigma_cp, tau_rdc_max)
    tau_rdc = max(tau_rdc_min, tau_rdc_comp)

    # LOGS
    logs.append(Log('General verification procedure', color='cyan', upper_case=True))
    logs.append(Log('a) detailed verification of the shear resistance may be omitted, provided that:', indent=1))
    logs.append(Log(f'tau_ed <= tau_rdc_min -> {tau_ed}<={tau_rdc_min} ¿?', indent=1))
    logs.append(Log('b) no calculated shear reinforcement is required in regions of the members where:', indent=1))
    logs.append(Log(f'tau_ed <= tau_rdc -> {tau_ed}<={tau_rdc} ¿?', indent=1))
    logs.append(Log('c) otherwise, shear reinforcement shall be designed according to 8.2.3 and 8.4.4:', indent=1))
    # logs.append(Log(f'tau_ed <= tau_rd -> {tau_ed}<={tau_rd} ¿?', indent=1))

    logs.append(
        Log('8.2.2 Detailed verification for members without shear reinforcement', color='cyan', upper_case=True)
    )
    logs.append(Log(f'- tau_rdc_min = {tau_rdc_min:0.2f} MPa', indent=1))
    logs.append(Log(f'- ddg = {ddg:0.1f} mm', indent=1))
    logs.append(Log(f'- rho_l = {rho_l:0.3f}', indent=1))
    logs.append(Log(f'- tau_rdc_0 = {tau_rdc_0:0.2f} MPa', indent=1))
    # bw The width bw for cross-sections with variable width and for circular cross-sections is defined in 8.2.3(9);


# 9.2 STRESS LIMITATION AND CRACK CONTROL
# 9.2.2 Minimum reinforcement areas to avoid yielding
def min_reinf(NEd, b, h, fct_eff, fyk):
    """9.2.2 Minimum reinforcement areas to avoid yielding according to EN 1992-1-1:2023.

    Calculate the required minimum reinforcement area to avoid yielding for a given section when sections cracks.
    Minimum reinforcement should be determined for the individual parts of the section (webs, flanges)
    and not for the whole section in sections like T-beams or box girders.

    Args:
        NEd (float): SLS axial force applied on the section or rectangle (compressions are negative) in kN.
        b (float): The width of the section or rectangle in meters.
        h (float): The height of the section or rectangle in meters.
        fct_eff (float): Effective tension strength of concrete (normally the mean tensile strength) in MPa.
        fyk (float): Characteristic yield strength of steel in MPa.
    """
    As_min_y1, As_min_y2 = sls9.As_min_y(NEd, b, h, fct_eff, fyk)

    results = {}
    logs = []
    results['As_min_y1'] = As_min_y1
    results['As_min_y2'] = As_min_y2
    logs.append(Log('Minimum reinforcement areas to avoid yielding according to 9.2.2 EN 1992-1-1:2023'))
    logs.append(Log(f'As_min_y1 = {As_min_y1} mm²'))
    logs.append(Log(f'As_min_y2 = {As_min_y2} mm²'))
    return results, logs


# 9.2.3 Refined control of cracking
def crack_width(
    fck: float,
    xg: float,
    c: float,
    x: float,
    sigma_s: float,
    As: float,
    phi_eq: float,
    h: float = None,
    b: float = None,
    diameter: float = None,
    Ap: float = None,
    phi_p: float = None,
    hc_eff: float = None,
    Ac_eff: float = None,
    rho_p_eff: float = None,
    kt: float = None,
    fct_eff: float = None,
    alphae: float = None,
    kw: float = None,
    Es: float = None,
    xi: float = None,
    kb: float = None,
):
    """Calculates the refined control of cracking according to EN 1992-1-1:2023 (Section 9.2.3).

    Provides an estimate of the crack width at the member surface at the most extreme fibre.
    For other locations, 'c' can be replaced by the distance from the bar considered and k1/r can be adjusted
    accordingly.

    Args:
        fck (float): Characteristic compressive strength of concrete (MPa).
        xg (float): Depth of centroid of section measured from compressed fibre (mm).
        c (float): Concrete cover of reinforcement to bar surface (mm). Larger value of lateral and vertical cover
        should be applied.
        x (float): Depth of the neutral axis of the cracked section measured from compressed fibre (mm).
        sigma_s (float): Tension in most tensioned bar according to fully cracked analysis (MPa).
        As (float): Area of longitudinal reinforcement (mm²).
        phi_eq (float): diameter of longitudinal reinforcement (mm). See eq. (9.19).
        h (float): Height of the section (mm). Required for rectangular cross sections.
        b (float): Width of the section (mm) Required for rectangular cross sections.
        diameter (float): diameter of the circular section (mm). Required for circular cross sections.
        Ap (float, optional): Area of prestressing steel (mm²). Default is 0.
        phi_p (float, optional): Diameter of prestressing steel (mm). Default is 0.
        hc_eff (float, optional): Height of the effective tensioned concrete area (mm).
        Ac_eff (float, optional): Effective area of concrete in tension surrounding the reinforcement or prestressing
        tendons of depth hc_eff (mm²). If None, it is calculated for rectangular and circular section.
        rho_p_eff (float, optional): Effective tension reinforcement ratio.
        kt (float, optional): Factor accounting for tension stiffening. Default is 0.4 (long term).
        fct_eff (float, optional): Effective tension strength of concrete (can normally be taken as the mean tensile
        strength) in MPa.
        alphae (float, optional): Modular ratio Es/Ecm.
        kw (float, optional): Factor that converts the mean crack spacing to a characteristic value. (Default is 1.7
        unless the National Annex gives a different value)
        Es (float, optional): Modulus of elasticity of steel bars (MPa) (Default Es=200000 MPa).
        xi (float, optional): Ratio of bond strength according to Table 10.1 in 10.3(2). Default is for ribbed bars and
        fck≤50.
        kb (float): Factor accounting for bond conditions of bar [1.2 poor bond, 0.9 good bond]. Default is 0.9
        (see Eq. 9.18).

    Returns:
        tuple: (result, logs)
            result (dict): Dictionary with the results of the calculation.
            logs (list): List of logs describing the process.
    """
    results = {}
    logs = []
    logs.append(Log('9.2.3. Refined control of cracking according to EN 1992-1-1:2023', color='cyan', upper_case=True))
    logs.append(Log('Assumptions', color='cyan', upper_case=True))
    logs.append(Log('- Calculated in the most tensioned fibre.', indent=1))

    ay_i = c + phi_eq / 2

    if diameter is not None:
        section_type = 'Circular'
        _Ac_eff, _hc_eff = _sls9.Ac_eff(x, ay_i, phi_eq, diameter=diameter, section_type='circular')
        h = diameter
    elif b is not None and h is not None:
        section_type = 'Rectangular'
        _Ac_eff, _hc_eff = _sls9.Ac_eff(x, ay_i, phi_eq, h=h, b=b)
    else:
        section_type = 'Generic'
        if Ac_eff is None:
            raise ValueError('Ac_eff must be provided for non rectangular/circular cross sections')
        if hc_eff is None:
            raise ValueError('hc_eff must be provided for non rectangular/circular cross sections')
        _Ac_eff, _hc_eff = Ac_eff, hc_eff

    logs.append(Log(f'- {section_type} cross section', indent=1))

    if Ac_eff is None:
        Ac_eff = _Ac_eff
        logs.append(Log(f'- Ac_eff = {Ac_eff:0.2f} m²', indent=1))
    if hc_eff is None:
        hc_eff = _hc_eff
        logs.append(Log(f'- hc_eff = {hc_eff:0.2f} m', indent=1))
    if fct_eff is None:
        fct_eff = mat5.fctm(fck)
        logs.append(Log(f'- fct_eff is the mean tensile strength at 28 days ({fct_eff:0.2f} MPa)', indent=1))
    if Es is None:
        Es = 200000
        logs.append(Log(f'- Es = {Es:0.0f} MPa', indent=1))
    if alphae is None:
        fcm = mat5.fcm(fck)
        Ecm = mat5.Ecm(fcm)
        alphae = Es / Ecm
        logs.append(Log(f'- Ecm = {Ecm:0.0f} MPa', indent=1))
    if Ap is None:
        Ap = 0
        phi_p = 0
        logs.append(Log('- No prestressing steel -> Ap=0, phi_p=0', indent=1))

    if kt is None:
        kt = 0.4
        logs.append(Log(f'- kt = {kt:0.1f} (long term)', indent=1))
    if rho_p_eff is None:
        if xi is None:
            xi = 0.7
            logs.append(Log('- xi=0.7 -> ribbed bars (fck ≤ 50)', indent=1))
        xi1 = _sls9.xi1(xi, phi_p, phi_eq)
        logs.append(Log(f'- xi1={xi1:0.2f}', indent=1))
        rho_p_eff = _sls9.rho_p_eff(As, xi1, Ap, Ac_eff)

        logs.append(Log(f'- rho_p_eff = {rho_p_eff:0.3f} (Eq. 9.12)', indent=1))
    if kw is None:
        kw = 1.7
        logs.append(Log(f'- kw = {kw:0.1f}', indent=1))
    if kb is None:
        kb = 0.9
        logs.append(Log(f'- kb = {kb:0.1f} (good bond conditions)', indent=1))

    k_1_r_ = sls9.k_1_r(h, x, ay_i)
    kfl = sls9.kfl(h, xg, hc_eff)
    srm_cal_ = sls9.srm_cal(c, kfl, kb, phi_eq, rho_p_eff, kw, h, x)
    epssm_epscm_ = sls9.epssm_epscm(sigma_s, kt, fct_eff, rho_p_eff, alphae, Es)
    wk_cal_ = kw * k_1_r_ * srm_cal_ * epssm_epscm_

    results['wk_cal'] = wk_cal_
    results['kw'] = kw
    results['k_1_r'] = k_1_r_
    results['ay,i'] = ay_i
    results['h'] = h
    results['x'] = x

    logs.append(Log('\nCalculated surface crack width (Eq 9.8):', color='cyan', upper_case=True))
    logs.append(Log(f'wk_cal = {wk_cal_:0.3f} mm'))
    logs.append(Log(f'kw = {kw:0.1f}', indent=1))
    logs.append(Log(f'k_1_r = {k_1_r_:0.3f} (Eq. 9.9)', indent=1))
    logs.append(Log(f'ay,i = {ay_i:0.1f} mm', indent=2))
    logs.append(Log(f'h = {h:0.1f} mm', indent=2))
    logs.append(Log(f'x = {x:0.1f} mm', indent=2))

    results['epssm_epscm'] = epssm_epscm_
    results['kt'] = kt
    results['fct_eff'] = fct_eff
    results['rho_p_eff'] = rho_p_eff
    results['As'] = As
    results['Ap'] = Ap
    results['Ac_eff'] = Ac_eff
    results['alphae'] = alphae
    results['Es'] = Es

    logs.append(Log(f'epssm_epscm = {epssm_epscm_ * 1e3:0.3f} mm/m (Eq. 9.11)', indent=1))
    logs.append(
        Log(
            f'sigma_s = {sigma_s:0.2f} MPa (in the tension reinforcement closest to the tensioned concrete surface)',
            indent=2,
        )
    )
    logs.append(Log(f'kt = {kt:0.2f}', indent=2))
    logs.append(Log(f'fct_eff = {fct_eff:0.2f} MPa', indent=2))
    logs.append(Log(f'rho_p_eff = {rho_p_eff:0.3f}', indent=2))
    logs.append(Log(f'As = {As:0.1f} mm²', indent=3))
    logs.append(Log(f'Ap = {Ap:0.1f} mm²', indent=3))
    logs.append(Log(f'xi1 = {xi1:0.2f}', indent=3))
    logs.append(Log(f'Ac,eff = {Ac_eff:0.1f} mm²', indent=3))
    logs.append(Log(f'alphae = {alphae:0.2f}', indent=2))
    logs.append(Log(f'Es = {Es:0.0f} MPa', indent=2))

    results['srm_cal'] = srm_cal_
    results['c'] = c
    results['kfl'] = kfl
    results['xg'] = xg
    results['hc_eff'] = hc_eff
    results['kb'] = kb
    results['phi'] = phi_eq

    logs.append(Log(f'srm_cal = {srm_cal_:0.1f} mm', indent=1))
    logs.append(Log(f'c = {c:0.1f} mm', indent=2))
    logs.append(Log(f'kfl = {kfl:0.2f}', indent=2))
    logs.append(Log(f'xg = {xg:0.1f} mm', indent=3))
    logs.append(Log(f'hc_eff = {hc_eff:0.1f} mm', indent=3))
    logs.append(Log(f'kb = {kb:0.1f}', indent=2))
    logs.append(Log(f'phi = {phi_eq:0.1f} mm', indent=2))
    logs.append(Log(f'rho_p_eff = {rho_p_eff:0.3f}', indent=2))

    return results, logs
